import{_ as t,o as a,c as s,a3 as o}from"./chunks/framework.BveOjhN0.js";const p=JSON.parse('{"title":"Tasks — User Guide","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Tasks — User Guide | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/user-guide/tasks"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Tasks — User Guide | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/user-guide/tasks"}]]},"headers":[],"relativePath":"user-guide/tasks.md","filePath":"user-guide/tasks.md","lastUpdated":1784926677000}'),r={name:"user-guide/tasks.md"};function n(i,e,d,l,c,h){return a(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="tasks-—-user-guide" tabindex="-1">Tasks — User Guide <a class="header-anchor" href="#tasks-—-user-guide" aria-label="Permalink to &quot;Tasks — User Guide&quot;">​</a></h1><h2 id="who-can-use-tasks" tabindex="-1">Who can use Tasks <a class="header-anchor" href="#who-can-use-tasks" aria-label="Permalink to &quot;Who can use Tasks&quot;">​</a></h2><p>Your workspace must have the <strong>Tasks</strong> module installed (included by default on new workspaces). Your role must include the relevant permissions (<code>view</code>, <code>create</code>, <code>update</code>, <code>delete</code>, <code>assign</code>, <code>complete</code>, <code>change_due_date</code> as needed).</p><p>Without <strong>assign</strong>, you only see tasks assigned to you.</p><h2 id="board-list" tabindex="-1">Board &amp; list <a class="header-anchor" href="#board-list" aria-label="Permalink to &quot;Board &amp; list&quot;">​</a></h2><p>Open <strong>Tasks</strong> from the sidebar. The default view is the <strong>Board</strong> (columns by status). Switch to <strong>List</strong> for a table.</p><ul><li>Search by title or description</li><li>Filter by status, priority, and assignee</li><li>KPI cards summarize totals, due today / this week, overdue, and completion metrics for your scope</li></ul><p>Status labels in the UI:</p><table tabindex="0"><thead><tr><th>Value</th><th>Label</th></tr></thead><tbody><tr><td><code>open</code></td><td>To Do</td></tr><tr><td><code>in_progress</code></td><td>In Progress</td></tr><tr><td><code>waiting</code></td><td>Waiting</td></tr><tr><td><code>completed</code></td><td>Completed</td></tr><tr><td><code>cancelled</code></td><td>Cancelled</td></tr></tbody></table><h2 id="create-edit" tabindex="-1">Create &amp; edit <a class="header-anchor" href="#create-edit" aria-label="Permalink to &quot;Create &amp; edit&quot;">​</a></h2><ol><li>Click <strong>New task</strong></li><li>Enter title (required) and optional description, status, priority, due date, and assignee</li><li>Save</li></ol><p>Edit from the row menu or the detail drawer. Dragging a card on the board proposes a status change; <strong>Save</strong> in the drawer commits it (Cancel restores the card).</p><h2 id="due-dates" tabindex="-1">Due dates <a class="header-anchor" href="#due-dates" aria-label="Permalink to &quot;Due dates&quot;">​</a></h2><p>You can set a due date when creating a task. Changing the due date later requires the <strong>change due date</strong> permission (<code>tasks.change_due_date</code>).</p><p>When a task is due today or overdue, you get an <strong>in-app</strong> notification for that task. Once per day (at the workspace <strong>Daily Reminder Time</strong> in Settings → General, default 09:00 local), each assignee with due or overdue tasks also receives <strong>one consolidated email</strong> with links to those tasks.</p><p>At the same <strong>Daily Reminder Time</strong>, the workspace also sends a <strong>daily CRM summary</strong> email (leads by open stage, open tasks by status, scheduled meetings). Users without <strong>Receive all-users daily summary</strong> get only their own counts. Users with that flag get a user-wise summary for everyone in the workspace instead (not both).</p><h2 id="assignment" tabindex="-1">Assignment <a class="header-anchor" href="#assignment" aria-label="Permalink to &quot;Assignment&quot;">​</a></h2><p>Users with <strong>assign</strong> can set or clear the assignee. The assignee receives an in-app and email notification when someone else assigns them.</p><h2 id="complete-reopen" tabindex="-1">Complete &amp; reopen <a class="header-anchor" href="#complete-reopen" aria-label="Permalink to &quot;Complete &amp; reopen&quot;">​</a></h2><p>Users with <strong>complete</strong> can mark a task completed (sets <code>completed_at</code>) or reopen it from the detail drawer.</p><h2 id="comments-history" tabindex="-1">Comments &amp; history <a class="header-anchor" href="#comments-history" aria-label="Permalink to &quot;Comments &amp; history&quot;">​</a></h2><ul><li><strong>Comments</strong> — free-form notes (stored as task notes)</li><li><strong>History</strong> — activity timeline (create, update, assignment, complete, reopen, note, etc.)</li></ul>',22)])])}const u=t(r,[["render",n]]);export{p as __pageData,u as default};
